import { auth } from "@/lib/auth"
import { NextResponse } from "next/server"
import type { NextRequest } from "next/server"

export async function proxy(request: NextRequest) {
  const session = await auth()
  const { nextUrl } = request
  const isLoggedIn = !!session
  const role = session?.user?.role?.toLowerCase()

  const isAuthRoute = nextUrl.pathname.startsWith("/login")
  const isProtected = nextUrl.pathname.startsWith("/student") || 
                      nextUrl.pathname.startsWith("/teacher") || 
                      nextUrl.pathname.startsWith("/admin")

  // Redirect logged-in users away from auth routes to their dashboards
  if (isAuthRoute) {
    if (isLoggedIn) {
      return NextResponse.redirect(new URL(`/${role}/dashboard`, nextUrl))
    }
    return null
  }

  // Protect private routes
  if (isProtected) {
    if (!isLoggedIn) {
      return NextResponse.redirect(new URL("/login", nextUrl))
    }

    // Role-based route bounding
    if (nextUrl.pathname.startsWith("/admin") && role !== "admin") {
      return NextResponse.redirect(new URL(`/${role}/dashboard`, nextUrl))
    }
    if (nextUrl.pathname.startsWith("/student") && role !== "student") {
      return NextResponse.redirect(new URL(`/${role}/dashboard`, nextUrl))
    }
    if (nextUrl.pathname.startsWith("/teacher") && role !== "teacher") {
      return NextResponse.redirect(new URL(`/${role}/dashboard`, nextUrl))
    }
  }

  return NextResponse.next()
}

// Specify which routes this proxy runs on
export const config = {
  matcher: ["/((?!api|_next/static|_next/image|favicon.ico).*)"],
}

